styles.css:
/* Styles pour les métadonnées de recettes */
.meta-recette {
    background-color: #f9f9f9;
    padding: 20px;
    border-radius: 8px;
    margin: 20px 0;
}

.meta-recette p {
    margin: 10px 0;
}

.ingredients {
    margin-top: 20px;
    padding: 15px;
    background-color: #fff;
    border-left: 4px solid var(--wp--preset--color--primary);
}

/* Styles pour la grille de recettes */
.wp-block-post-template {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 30px;
}

/* Styles généraux du thème */
body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    font-size: 16px;
    color: #333333;
    margin: 0 20px; /* marge gauche/droite de 20px */
    padding: 0;
    background: linear-gradient(to bottom, #f0f0f0, #ffffff); /* dégradé gris vers blanc */
}

/* Header */
.site-header {
    margin: 0 20px; /* marge gauche/droite */
    padding: 20px 0;
}

/* Conteneur principal */
.site {
    max-width: 1200px;
    margin: 0 auto;
    padding: 20px;
}

/* Footer */
.site-footer {
    margin: 0 20px; /* marge gauche/droite */
    text-align: center;
    padding: 40px 0;
    background-color: #f2f2f2;
    color: #666666;
}

/* Liens */
a {
    color: #4ECDC4; /* couleur secondaire */
    text-decoration: none;
}

a:hover {
    text-decoration: underline;
}

/* Titres */
h1, h2, h3, h4, h5, h6 {
    color: #222222;
    margin-top: 1.2em;
    margin-bottom: 0.6em;
    line-height: 1.3;
}

/* Paragraphes */
p {
    line-height: 1.6;
    margin-bottom: 1em;
}

/* Images mises en avant */
.wp-block-post-featured-image img {
    max-width: 100%;
    height: auto;
    border-radius: 8px;
    margin-bottom: 20px;
}

/* Styles pour les métadonnées des recettes */
.champs-recette {
    background-color: #fafafa;
    padding: 20px;
    border-radius: 8px;
    margin: 20px 0;
    border-left: 4px solid #FF6B6B; /* couleur primaire */
}

.champs-recette-row {
    display: flex;
    justify-content: space-between;
    margin-bottom: 10px;
}

.champs-recette-label {
    font-weight: bold;
    color: #555555;
}

.champs-recette-value {
    color: #333333;
}

/* Section ingrédients */
.ingredients {
    background-color: #ffffff;
    border-left: 4px solid #4ECDC4; /* couleur secondaire */
    padding: 15px;
    margin-top: 20px;
    border-radius: 6px;
}

.ingredients h3 {
    margin-top: 0;
}

/* Grille des articles / archives */
.wp-block-post-template {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 30px;
}

/* Grid : cartes plus larges, moins nombreuses */
.recipe-cards-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 2.5rem;
}

/* Card */
.recipe-card {
  background: #fafafa;
  border-radius: 0;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

/* Image très dominante */
.recipe-card__image img {
  width: 100%;
  height: 320px;
  object-fit: cover;
  display: block;
}

/* Contenu centré, style éditorial */
.recipe-card__content {
  padding: 1.75rem 1.5rem 1.25rem;
  text-align: center;
}

/* Titre : typographie magazine */
.recipe-card__title {
  font-size: 1.4rem;
  font-weight: 800;
  line-height: 1.25;
  margin: 0 0 0.75rem;
}

/* Meta très discrète */
.recipe-card__meta {
  font-size: 0.8rem;
  color: #888;
  margin-bottom: 1.25rem;
}

/* Footer séparé visuellement */
.recipe-card__footer {
  padding: 1.25rem 1.5rem;
  background: #fff;
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 0.75rem;
}

/* Tags minimalistes */
.tag {
  font-size: 0.7rem;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  padding: 0.35em 0.8em;
  border: 1px solid #ddd;
  background: transparent;
  color: #444;
}

/* Difficulté en badge texte */
.difficulty {
  font-size: 0.7rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

.difficulty.facile { color: #1f7a4f; }
.difficulty.moyen { color: #9a6700; }
.difficulty.difficile { color: #a61b1b; }

/* Bouton sobre, type lien éditorial */
.button {
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 0.6em 1.2em;
  border: 1px solid #000;
  background: transparent;
  color: #000;
  text-decoration: none;
}
